cd /home/janfr/dev/pc-switcher
_GSD_SHIM_NAME="gsd-tools.cjs"; GSD_TOOLS="$HOME/.claude/gsd-core/bin/${_GSD_SHIM_NAME}"; gsd_run() { node "$GSD_TOOLS" "$@"; }
PHASE_DIR=".planning/phases/01-home-sync-mvp-user-data-sync"
PADDED_PHASE="01"
echo "=== depth config ==="
gsd_run query config-get workflow.code_review_depth 2>/dev/null || echo "(unset -> standard)"
echo "=== commit_docs ==="
gsd_run query config-get commit_docs 2>/dev/null || echo "(unset)"
echo ""
echo "=== file scope from SUMMARY.md key_files ==="
REVIEW_FILES=()
for summary in "$PHASE_DIR"/*-SUMMARY.md; do
  EXTRACTED=$(node -e "
    const fs = require('fs');
    const content = fs.readFileSync('$summary', 'utf-8');
    const match = content.match(/^---\n([\s\S]*?)\n---/);
    if (!match) { process.exit(0); }
    const yaml = match[1];
    const files = [];
    let inSection = null;
    for (const line of yaml.split('\n')) {
      if (/^\s+created:/.test(line)) { inSection = 'created'; continue; }
      if (/^\s+modified:/.test(line)) { inSection = 'modified'; continue; }
      if (/^\s*[\w-]+:/.test(line) && !/^\s*-/.test(line)) { inSection = null; continue; }
      if (inSection && /^\s+-\s+(.+)/.test(line)) {
        let raw = line.match(/^\s+-\s+(.+)/)[1].trim();
        raw = raw.replace(/^['\"]|['\"]\$/g, '');
        raw = raw.replace(/\s+\([^)]*\)\s*\$/, '');
        raw = raw.split(/\s+—\s/)[0].trim();
        if (/\//.test(raw) && /\.[A-Za-z0-9]+\$/.test(raw)) { files.push(raw); }
      }
    }
    if (files.length) console.log(files.join('\n'));
  " 2>/dev/null)
  [ -n "$EXTRACTED" ] && while IFS= read -r f; do [ -n "$f" ] && REVIEW_FILES+=("$f"); done <<< "$EXTRACTED"
done
# filter planning + deleted, dedupe
printf '%s\n' "${REVIEW_FILES[@]}" | grep -vE '^\.planning/|-SUMMARY\.md$|-PLAN\.md$' | sort -u | while IFS= read -r f; do
  [ -f "$f" ] && echo "EXISTS: $f" || echo "MISSING: $f"
done
